```plantuml
@startuml
package surcharge {
    package seat {
        enum SeatType {
            FreeSeat
            ReservedSeat
            + abstract createSeat(superExpress : SuperExpress) : Seat
        }

        interface Seat {
            + getSeatSurcharge()
        }

        class FreeSeat {
            - Hikari
            + getSeatSurcharge() : Yen
        }

        class ReservedSeat {
            - SuperExpress
            + getSeatSurcharge() : Yen
        }

        SeatType o--> Seat
        Seat <|.. FreeSeat
        Seat <|.. ReservedSeat
    }

    package superexpress {
        enum ShinkansenType {
            Hikari
            Nozomi
            + abstract createSuperExpress(destination : Destination) : SuperExpress
        }

        interface SuperExpress {
            + getSuperExpressSurcharge() : Yen
        }

        enum Hikari {
            ShinOsaka
            Himeji
            + getSuperExpressSurcharge() : Yen
        }

        enum Nozomi {
            ShinOsaka
            Himeji
            + getSuperExpressSurcharge() : Yen
        }

        ShinkansenType o--> SuperExpress
        SuperExpress <|.. Hikari
        SuperExpress <|.. Nozomi
    }

    FreeSeat o--> Hikari
    ReservedSeat o--> SuperExpress
}
@enduml
```
